class Solution(object):
    def numberOfAlternatingGroups(self, colors, k):
        n = len(colors)
        extended = colors + colors[:k - 1]
        count = 0
        alt = 0
        for i in range(1, len(extended)):
            if extended[i] != extended[i - 1]:
                alt += 1
            else:
                alt = 0
            if i >= k - 1 and alt >= k - 1:
                count += 1
        return count
